class Solution {
    public int longestSubsequence(String s, int k) {
        int count = 0;
        int i = s.length() - 1;
        while (i >= 0 && k >= 0) {
            if (s.charAt(i) == '0') {
                count++;
                i--;
            } else if (k > 0) {
                count++;
                k--;
                i--;
            } else {
                i--;
            }
        }
        while (i >= 0) {
            if (s.charAt(i) == '0') {
                count++;
            }
            i--;
        }
        return count;
    }
}
```
